+        let app_state = AppState::new().with(limiter.clone());
+        let allowed_count = Arc::new(AtomicUsize::new(0));
+        let denied_count = Arc::new(AtomicUsize::new(0));
+
+        let handles: Vec<_> = (0..NUM_CLIENTS)
